// staleCutoff returns the unix-seconds boundary: anything contacted at or
// before this is considered stale.
func staleCutoff(now int64, days int) int64 {
	return now - int64(days)*86400
}

// runStale lists cold open opportunities. A NULL/zero date_last_contacted is
// treated as MAXIMALLY stale (never contacted) — those deals are the most
// urgent to surface, so they sort first. days_stale is computed from the
// last-contacted timestamp; for never-contacted rows it is reported as -1 to
// signal "unknown / never".
func runStale(ctx context.Context, db *sql.DB, opts staleOpts, now int64) ([]staleOpp, error) {
	status := opts.Status
	if status == "" {
		status = "Open"
	}
	cutoff := staleCutoff(now, opts.Days)

	query := `
		SELECT
			id,
			COALESCE(name, '') AS name,
			COALESCE(monetary_value, 0) AS monetary_value,
			json_extract(data,'$.date_last_contacted') AS last_contacted
		FROM opportunities
		WHERE status = ?
		  AND (
		        json_extract(data,'$.date_last_contacted') IS NULL
		     OR json_extract(data,'$.date_last_contacted') <= ?
		  )`
	queryArgs := []any{status, cutoff}
	if opts.Pipeline != "" {
		query += " AND pipeline_id = ?"
		queryArgs = append(queryArgs, opts.Pipeline)
	}
	// Never-contacted (NULL) first, then oldest contact first, then biggest value.
	query += `
		ORDER BY (json_extract(data,'$.date_last_contacted') IS NULL) DESC,
		         json_extract(data,'$.date_last_contacted') ASC,
		         monetary_value DESC`
	if opts.Limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
	}

	rows, err := db.QueryContext(ctx, query, queryArgs...)
	if err != nil {
		return nil, fmt.Errorf("querying opportunities: %w", err)
	}
	defer rows.Close()

	var out []staleOpp
	for rows.Next() {
		var id, name string
		var value float64
		var last sql.NullInt64
		if err := rows.Scan(&id, &name, &value, &last); err != nil {
			return nil, fmt.Errorf("scanning stale row: %w", err)
		}
		o := staleOpp{ID: id, Name: name, MonetaryValue: value}
		if last.Valid && last.Int64 > 0 {
			o.LastContacted = last.Int64
			o.DaysStale = int((now - last.Int64) / 86400)
		} else {
			o.DaysStale = -1 // never contacted
		}
		out = append(out, o)
	}
	return out, rows.Err()
}

// runStaleByAssignee aggregates cold-deal count and value per owner.
func runStaleByAssignee(ctx context.Context, db *sql.DB, opts staleOpts, now int64) ([]staleByAssignee, error) {
	status := opts.Status
	if status == "" {
		status = "Open"
	}
	cutoff := staleCutoff(now, opts.Days)

	query := `
		SELECT
			COALESCE(CAST(json_extract(data,'$.assignee_id') AS TEXT), '(unassigned)') AS assignee,
			COUNT(*) AS cold_count,
			COALESCE(SUM(monetary_value), 0) AS cold_value
		FROM opportunities
		WHERE status = ?
		  AND (
		        json_extract(data,'$.date_last_contacted') IS NULL
		     OR json_extract(data,'$.date_last_contacted') <= ?
		  )`
	queryArgs := []any{status, cutoff}
	if opts.Pipeline != "" {
		query += " AND pipeline_id = ?"
		queryArgs = append(queryArgs, opts.Pipeline)
	}
	query += " GROUP BY assignee ORDER BY cold_value DESC"

	rows, err := db.QueryContext(ctx, query, queryArgs...)
	if err != nil {
		return nil, fmt.Errorf("querying opportunities: %w", err)
	}
	defer rows.Close()

	var out []staleByAssignee
	for rows.Next() {
		var g staleByAssignee
		if err := rows.Scan(&g.AssigneeID, &g.ColdCount, &g.ColdValue); err != nil {
			return nil, fmt.Errorf("scanning stale-by-assignee row: %w", err)
		}
		out = append(out, g)
	}
	return out, rows.Err()
}

